mapper.insert:
INSERT INTO archive_file_info (
      board_id
    , original_name
    , save_name
    , size
    , delete_yn
    , created_date
    , deleted_date
) VALUES

(
      #{file.boardId}
    , #{file.originalName}
    , #{file.saveName}
    , #{file.size}
    , 0
    , NOW()
    , NULL
)

mapper.select:
SELECT file_id , board_id , original_name , save_name , size , delete_yn , created_date , deleted_date FROM archive_file_info WHERE delete_yn = 0 AND file_id IN
#{id}
ORDER BY file_id
